class Solution {
    public int getMaxRepetitions(String s1, int n1, String s2, int n2) {
        if (s1.length() == 0 || s2.length() == 0 || n1 == 0 || n2 == 0) {
            return 0;
        }
        int count = 0;
        int j = 0;
        int[] s2Count = new int[s1.length() + 1];
        int[] s2Index = new int[s1.length() + 1];
        for (int i = 1; i <= n1; i++) {
            for (int k = 0; k < s1.length(); k++) {
                if (s1.charAt(k) == s2.charAt(j)) {
                    j++;
                    if (j == s2.length()) {
                        count++;
                        j = 0;
                    }
                }
            }
            s2Count[i] = count;
            s2Index[i] = j;
            for (int l = 0; l < i; l++) {
                if (s2Index[l] == j) {
                    int prefixCount = s2Count[l];
                    int patternCount = (s2Count[i] - s2Count[l]) * ((n1 - l) / (i - l));
                    int suffixCount = s2Count[l + (n1 - l) % (i - l)] - s2Count[l];
                    return (prefixCount + patternCount + suffixCount) / n2;
                }
            }
        }
        return s2Count[n1] / n2;
    }
}
